('computer-science:1-2-1-primary-storage-memory:fib:2b2d7d20', 'computer-science', 'computer-science:1-2-1-primary-storage-memory', '1.2.1 Primary Storage (Memory)', 'fib', 'fib', 1, '{"question": "Data that is moved out of RAM into virtual memory is brought back in again when it is next _____.", "blankOptions": {"B1": ["non-volatile", "virtual", "needed", "volatile"]}}'::jsonb, '{"blanks": {"B1": "needed"}}'::jsonb),
