('computer-science:1-2-2-secondary-storage:match:b7b9735b', 'computer-science', 'computer-science:1-2-2-secondary-storage', '1.2.2 Secondary Storage', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Capacity”?", "options": ["How much data a storage device can hold", "Fits a device that gets carried between locations and dropped often", "Fits a laptop that must boot up and load programs quickly", "How consistently a device keeps working over time without failing or corrupting data"]}'::jsonb, '{"answer": 0, "explain": "“Capacity” means: How much data a storage device can hold"}'::jsonb),
