('computer-science:1-2-2-secondary-storage:match:0a3cc1c0', 'computer-science', 'computer-science:1-2-2-secondary-storage', '1.2.2 Secondary Storage', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Portability”?", "options": ["Stores data by magnetising areas of a spinning disk or a length of tape", "How well a device withstands physical damage, such as being dropped or knocked", "Fits a device that gets carried between locations and dropped often", "How easily a device can be physically carried and used with different computers"]}'::jsonb, '{"answer": 3, "explain": "“Portability” means: How easily a device can be physically carried and used with different computers"}'::jsonb),
('computer-science:1-2-2-secondary-storage:match:0a3674d0', 'computer-science', 'computer-science:1-2-2-secondary-storage', '1.2.2 Secondary Storage', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Durability”?", "options": ["How well a device withstands physical damage, such as being dropped or knocked", "Keeps its data even when the power is switched off", "Fits a desktop PC or server that never moves and needs huge capacity as cheaply as possible", "Stores data electronically in flash memory chips, with no moving parts"]}'::jsonb, '{"answer": 0, "explain": "“Durability” means: How well a device withstands physical damage, such as being dropped or knocked"}'::jsonb),
('computer-science:1-2-2-secondary-storage:match:25a3769b', 'computer-science', 'computer-science:1-2-2-secondary-storage', '1.2.2 Secondary Storage', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Reliability”?", "options": ["Fits a device that gets carried between locations and dropped often", "How consistently a device keeps working over time without failing or corrupting data", "The price of a device, usually compared per gigabyte so different sizes can be compared fairly", "How well a device withstands physical damage, such as being dropped or knocked"]}'::jsonb, '{"answer": 1, "explain": "“Reliability” means: How consistently a device keeps working over time without failing or corrupting data"}'::jsonb),
('computer-science:1-2-2-secondary-storage:match:aa974d77', 'computer-science', 'computer-science:1-2-2-secondary-storage', '1.2.2 Secondary Storage', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Cost”?", "options": ["How well a device withstands physical damage, such as being dropped or knocked", "Fits distributing millions of identical, cheap copies of a film or piece of software", "How consistently a device keeps working over time without failing or corrupting data", "The price of a device, usually compared per gigabyte so different sizes can be compared fairly"]}'::jsonb, '{"answer": 3, "explain": "“Cost” means: The price of a device, usually compared per gigabyte so different sizes can be compared fairly"}'::jsonb),
('computer-science:1-2-2-secondary-storage:match:3e1a5e28', 'computer-science', 'computer-science:1-2-2-secondary-storage', '1.2.2 Secondary Storage', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Non-volatile storage”?", "options": ["Stores data by magnetising areas of a spinning disk or a length of tape", "Stores data electronically in flash memory chips, with no moving parts", "Keeps its data even when the power is switched off", "How well a device withstands physical damage, such as being dropped or knocked"]}'::jsonb, '{"answer": 2, "explain": "“Non-volatile storage” means: Keeps its data even when the power is switched off"}'::jsonb),
('computer-science:1-2-2-secondary-storage:match:a4500f97', 'computer-science', 'computer-science:1-2-2-secondary-storage', '1.2.2 Secondary Storage', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Magnetic storage”?", "options": ["Fits a desktop PC or server that never moves and needs huge capacity as cheaply as possible", "The price of a device, usually compared per gigabyte so different sizes can be compared fairly", "Stores data by magnetising areas of a spinning disk or a length of tape", "How quickly data can be read from or written to a device"]}'::jsonb, '{"answer": 2, "explain": "“Magnetic storage” means: Stores data by magnetising areas of a spinning disk or a length of tape"}'::jsonb),
